import{_ as a,o as r,c as t,ae as h}from"./chunks/framework.CFyvOAXl.js";const s="/assets/GFS_Architecture.BFp9eJgu.png",n="/assets/GFS_State.a9ubdKVz.png",p="/assets/GFS_Flow.B4N370r8.png",_=JSON.parse(`{"title":"[SOSP'03] GFS 论文阅读","description":"","frontmatter":{},"headers":[],"relativePath":"program/paper/gfs.md","filePath":"program/paper/gfs.md","lastUpdated":1665801949000}`),c={name:"program/paper/gfs.md"};function i(o,e,l,u,m,k){return r(),t("div",null,[...e[0]||(e[0]=[h('<h1 id="sosp-03-gfs-论文阅读" tabindex="-1">[SOSP&#39;03] GFS 论文阅读 <a class="header-anchor" href="#sosp-03-gfs-论文阅读" aria-label="Permalink to &quot;[SOSP&#39;03] GFS 论文阅读&quot;">​</a></h1><p>在分布式系统领域，Google发表了三篇重要论文。分别是：</p><p><a href="https://research.google.com/archive/gfs-sosp2003.pdf" target="_blank" rel="noreferrer">《The Google File System》</a></p><p><a href="https://research.google/pubs/pub62/" target="_blank" rel="noreferrer">《MapReduce: Simplified Data Processing on Large Clusters》</a></p><p><a href="https://research.google.com/archive/bigtable-osdi06.pdf" target="_blank" rel="noreferrer">《Bigtable: A Distributed Storage System for Structured Data》</a></p><p>本文涉及的《The Google File System》发表于2003年，介绍google文件系统的设计思想、关键逻辑流程。重要内容是：整体架构设计,控制流与数据流分离，心跳，master管理元数据，租约机制，快照机制，命名空间读写锁，多副本排布考虑，数据重构，旧副本探测（chunk version number），垃圾回收，故障检测（checksum）等。</p><h2 id="关键词" tabindex="-1">关键词 <a class="header-anchor" href="#关键词" aria-label="Permalink to &quot;关键词&quot;">​</a></h2><p>故障容错，可扩展性，数据存储，集群存储</p><h2 id="_1-介绍" tabindex="-1">1 介绍 <a class="header-anchor" href="#_1-介绍" aria-label="Permalink to &quot;1 介绍&quot;">​</a></h2><p>第一、组件故障是常态而不是异常。</p><blockquote><p>故障原因：程序bug、OS bug、人为失误、磁盘、内存、网络、供电设备等。</p></blockquote><p>第二、文件较大。</p><p>第三、大部分文件的更新是通过追加新数据而不是覆盖已有数据。</p><h2 id="_2-设计概述" tabindex="-1">2 设计概述 <a class="header-anchor" href="#_2-设计概述" aria-label="Permalink to &quot;2 设计概述&quot;">​</a></h2><h3 id="_2-1-假设" tabindex="-1">2.1 假设 <a class="header-anchor" href="#_2-1-假设" aria-label="Permalink to &quot;2.1 假设&quot;">​</a></h3><ul><li>系统由可能经常故障的组件构成。</li><li>系统由一定数量的大文件组成。</li><li>负载主要由两种读组成：大的流式读和小的随机读。</li><li>负载有很多大的追加写。一旦写完成，文件将很少被修改。</li><li>系统必须为多客户端并发操作文件提供良好语义。</li><li>高可持续的带宽比低时延更重要。</li></ul><h3 id="_2-2-接口" tabindex="-1">2.2 接口 <a class="header-anchor" href="#_2-2-接口" aria-label="Permalink to &quot;2.2 接口&quot;">​</a></h3><p>文件在目录中以层次组织，并且以路径名标识。</p><p>支持通常的操作：create、delete、open、close、read、write。</p><p>此外支持：snapshot、record append。</p><h3 id="_2-3-架构" tabindex="-1">2.3 架构 <a class="header-anchor" href="#_2-3-架构" aria-label="Permalink to &quot;2.3 架构&quot;">​</a></h3><p>文件被拆分成定长的chunk。每个chunk由一个不可变且全局唯一的64位标识。每个chunk在多个chunk server复制，默认是3副本。</p><p>master维护所有的文件系统元数据。包括namespace、访问控制信息、从文件到chunk的映射以及chunk的位置。同时控制系统范围的活动，如：chunk 租约管理，失效chunk的垃圾回收，chunk server间的chunk 迁移。master通过与每个chunk server周期性的发送心跳消息进行通信来给它指令和收集它的状态。</p><p>链接到每个应用程序的GFS客户端实现了文件系统API，同时与master、chunk server通信，代表应用程序进行数据的读写。客户端与master交互获取元数据，但所有的数据通信都是到chunk server。</p><p><img src="'+s+'" alt="GFS 架构"></p><h3 id="_2-4-单master" tabindex="-1">2.4 单master <a class="header-anchor" href="#_2-4-单master" aria-label="Permalink to &quot;2.4 单master&quot;">​</a></h3><p>客户端需要询问master它需要和哪个chunk server通信。</p><p>客户端将这种信息缓存下来一段时间，然后在后续操作直接与chunk server交互。</p><h3 id="_2-5-chunk大小" tabindex="-1">2.5 chunk大小 <a class="header-anchor" href="#_2-5-chunk大小" aria-label="Permalink to &quot;2.5 chunk大小&quot;">​</a></h3><p>chunk size是关键设计参数之一，GFS中是64MB。</p><h3 id="_2-6-元数据" tabindex="-1">2.6 元数据 <a class="header-anchor" href="#_2-6-元数据" aria-label="Permalink to &quot;2.6 元数据&quot;">​</a></h3><p>master主要存储三种类型的元数据：文件和chunk namespace、文件到chunk的映射、每个chunk 副本的位置。</p><h4 id="_2-6-2-chunk的地址" tabindex="-1">2.6.2 chunk的地址 <a class="header-anchor" href="#_2-6-2-chunk的地址" aria-label="Permalink to &quot;2.6.2 chunk的地址&quot;">​</a></h4><p>master不会永久记录chunk server与chunk副本间的关系。master在启动时会轮询chunk server获取此类信息。</p><h4 id="_2-6-3-操作日志" tabindex="-1">2.6.3 操作日志 <a class="header-anchor" href="#_2-6-3-操作日志" aria-label="Permalink to &quot;2.6.3 操作日志&quot;">​</a></h4><p>操作日志包含关键的元数据变化历史记录。</p><p>master通过回放操作日志来恢复文件系统状态。</p><p>为减少启动时间，必须使得日志尽量小。当日志超过一定大小的时候，master就会进行check point。check point使用一个压缩的类B树结构。</p><h4 id="_2-7-一致性模型" tabindex="-1">2.7 一致性模型 <a class="header-anchor" href="#_2-7-一致性模型" aria-label="Permalink to &quot;2.7 一致性模型&quot;">​</a></h4><p>consistent: 所有的client可以看到相同的数据。</p><p>defined：当文件处于consistent状态，并且所有的client可以看到变化写入的内容。</p><p>inconsistent: 由于改变失败，不同的client看到不同的数据。</p><p><img src="'+n+'" alt="GFS 架构"></p><h2 id="_3-系统交互" tabindex="-1">3 系统交互 <a class="header-anchor" href="#_3-系统交互" aria-label="Permalink to &quot;3 系统交互&quot;">​</a></h2><p>描述client、master、chunk server之间的交互，来实现数据的改变，原子性的记录追加和快照。</p><h3 id="_3-1-租约和变更顺序" tabindex="-1">3.1 租约和变更顺序 <a class="header-anchor" href="#_3-1-租约和变更顺序" aria-label="Permalink to &quot;3.1 租约和变更顺序&quot;">​</a></h3><p>变更是指对诸如写操作或者追加操作等对文件的内容或者元数据进行改变的操作。</p><p>GFS采用租约机制来保证副本间的一致性变化。master授予一个chunk lease给primary副本。primary副本获得对chunk的一系列变更顺序。所有的副本都遵循这种顺序。</p><p>租约机制的设计目的是最小化master节点的管理开销。每个租约有60秒的超时时间。</p><p>图2，解释了控制流：</p><p><img src="'+p+'" alt="GFS 架构"></p><p>step1、client询问master，拥有chunk的租约的chunkserver以及其它副本的位置。如果没有chunk server拥有租约，master会选择其中一个副本授予租约。</p><p>step2、master回复primary副本的标识和其它副本的位置。client缓存了这些信息以便于后续的变更。client只有在primary副本不可达或者不再拥有租约的时候才会再次与master交互。</p><p>step3、client将数据推送到所有的副本。每个chunkserver将数据保存在LRU buffer cache中直到数据被使用或者淘汰过时。</p><p>step4、一旦所有副本确认接收到数据，client就向primary副本发送写请求。primary副本为所有的改变分配序列号并按照顺序应用到自己本地。</p><p>step5、primary副本推送写请求到所有的secondary副本。每个secondary副本按照primary副本指定的相同序列号顺序去应用改变。</p><p>step6、secondary副本回复primary副本，他们已经完成了操作。</p><p>step7、primary副本回复client。</p><h3 id="_3-2-数据流" tabindex="-1">3.2 数据流 <a class="header-anchor" href="#_3-2-数据流" aria-label="Permalink to &quot;3.2 数据流&quot;">​</a></h3><p>GFS将数据流与控制流解耦，以有效利用网络。</p><p>为避免网路瓶颈和延迟，每个机器都将数据转发给网络拓扑中最近的机器。</p><p>将B字节传输到R个副本的理想耗时是B/T + RL，其中T是网络吞吐量，L是在两台机器之间传输字节的时延。</p><h3 id="_3-4-快照" tabindex="-1">3.4 快照 <a class="header-anchor" href="#_3-4-快照" aria-label="Permalink to &quot;3.4 快照&quot;">​</a></h3><p>GFS使用标准的写时复制技术来实现快照。当master收到快照请求，它首先撤销快照请求中对应的未到期租约。</p><p>当租约被撤销或者过期，master会将操作日志记录到磁盘。然后通过复制源文件或者目录树的元数据，将日志记录应用到其内存状态。新创建的快照文件如同源文件一样指向相同的chunk。</p><p>在快照操作之后，客户端在第一次写chunk C时，它会向master发送一个请求来找到当前的lease holder。master注意到chunk C的引用计数大于1。master将延迟回应client，而是选择一个新的chunk handle C’。然后，master要求每个当前拥有C的副本的chunkserver创建一个名为C &#39;的chunk。通过在与原始chunk相同的chunkserver上创建新的chunk，我们确保数据可以在本地复制，而不是通过网络。master给一个副本授予新的chunk C&#39;的租约，并回应client让其正常写入块。</p><h2 id="_4-master的操作" tabindex="-1">4 master的操作 <a class="header-anchor" href="#_4-master的操作" aria-label="Permalink to &quot;4 master的操作&quot;">​</a></h2><p>master执行所有namespace的操作。此外，它管理全系统的chunk副本：进行排布决策，创建新chunk和新副本，并协调全系统的活动。</p><h3 id="_4-1-命名空间管理与锁定" tabindex="-1">4.1 命名空间管理与锁定 <a class="header-anchor" href="#_4-1-命名空间管理与锁定" aria-label="Permalink to &quot;4.1 命名空间管理与锁定&quot;">​</a></h3><p>考虑到许多master的操作持续较久，GFS支持多个操作并行，对命名空间的特性区域使用锁，来保证正确的序列化。</p><p>GFS将命名空间在逻辑上呈现为查找表，将完整的路径名映射到元数据。并利用前缀压缩技术，在内存中有效表达。而且命名空间树中的每个节点都有一个相关的读写锁。</p><p>master的每个操作在执行前需要获得一系列锁。</p><p>对目录加的读锁防止目录被删除、重命名、或者快照。对文件加的写锁会将同名文件的创建操作串行执行。</p><h3 id="_4-2-副本排布" tabindex="-1">4.2 副本排布 <a class="header-anchor" href="#_4-2-副本排布" aria-label="Permalink to &quot;4.2 副本排布&quot;">​</a></h3><p>GFS集群以多个level分布，通常分布在多个机架。</p><p>chunk副本的排布策略主要出于2个目的：第一、最大化数据可靠性和可用性。第二、最大化网络带宽利用率。</p><h3 id="_4-3-创建、重新复制、重新均衡" tabindex="-1">4.3 创建、重新复制、重新均衡 <a class="header-anchor" href="#_4-3-创建、重新复制、重新均衡" aria-label="Permalink to &quot;4.3 创建、重新复制、重新均衡&quot;">​</a></h3><p>chunk创建：当master创建块，空副本的放置考虑以下因素：</p><p>（1）将新副本放置在低于磁盘利用率均值的chunkserver。</p><p>（2）限制每个chunkserver最近创建的数量。</p><p>（3）chunk副本跨机甲。</p><p>chunk重新复制：当可用副本数量少于用户指定目标，master会重新复制chunk。此外，为防止复制流量挤压客户端流量，chunkserver会对通向源chunkserver服务器的读请求进行流控来限制耗费在复制上的带宽。</p><p>chunk重新均衡：master服务器会定期重新均衡副本。它会检查当前的副本分布，移动副本以达到更好的磁盘空间和负载均衡。</p><h3 id="_4-4-垃圾回收" tabindex="-1">4.4 垃圾回收 <a class="header-anchor" href="#_4-4-垃圾回收" aria-label="Permalink to &quot;4.4 垃圾回收&quot;">​</a></h3><p>当文件删除后，GFS不会立即去回收可用的物理存储空间。GFS只会在周期性的垃圾回收中惰性的处理。</p><h4 id="_4-4-1-机制" tabindex="-1">4.4.1 机制 <a class="header-anchor" href="#_4-4-1-机制" aria-label="Permalink to &quot;4.4.1 机制&quot;">​</a></h4><p>当应用程序删除文件，master会将删除操作立即记录到日志。但是，该文件仅会重命名为一个包含删除时间戳的隐藏名称，而不是马上恢复资源。在master定期扫描文件系统的命名空间期间，它会删除已经存在了超过三天的隐藏文件（时间可配置）。当隐藏文件从命名空间中删除后，它的内存中的元数据就被删除。</p><p>在对chunk命名空间进行扫描的类似时，master识别了孤立块并且擦除了这些块的元数据。在chunkserver与master的心跳的消息中，每个chunkserver会报告它拥有的chunk的集合，然后master服务器会回复不在master元数据中的块的标识。chunkserver就可以自由的删除这些chunk的副本。</p><h4 id="_4-4-2-讨论" tabindex="-1">4.4.2 讨论 <a class="header-anchor" href="#_4-4-2-讨论" aria-label="Permalink to &quot;4.4.2 讨论&quot;">​</a></h4><h3 id="_4-5-旧副本检测" tabindex="-1">4.5 旧副本检测 <a class="header-anchor" href="#_4-5-旧副本检测" aria-label="Permalink to &quot;4.5 旧副本检测&quot;">​</a></h3><p>如果一个chunkserver故障了，并且忽略了chunk的改变，那么chunk副本可能会变的过时。对于每个chunk，master服务器维护一个块版本号(chunk version number)，以区分最新的和过时的副本。</p><p>当master服务器对chunk授予新的租约时，会增加chunk版本号并且通知这些最新的副本。master和副本都会在他们的持久状态中记录新版本号。当其他某个副本当前不可用时，它的chunk版本号就不会增加。当chunkserver重启并报告chunk和相关版本号的集合时，master会检测到chunkserver有旧副本。当master看到版本号大于它所记录的，master认为它在授予租约时失败了，并将高版本号作为最新版本号。</p><p>master服务器在其常规垃圾回收中删除过时的副本。在垃圾回收之前，当它响应客户端请求时，它能够有效的判定一个过时副本不存在。作为另一个保护措施，master通知client时，会包含chunk版本号。然后，客户端或者chunksever在执行操作的时候会校验版本号。</p><h2 id="_5-故障容错和诊断" tabindex="-1">5 故障容错和诊断 <a class="header-anchor" href="#_5-故障容错和诊断" aria-label="Permalink to &quot;5 故障容错和诊断&quot;">​</a></h2><p>GFS系统设计的最大挑战之一是处理频繁的组件故障。</p><h3 id="_5-1-高可用性" tabindex="-1">5.1 高可用性 <a class="header-anchor" href="#_5-1-高可用性" aria-label="Permalink to &quot;5.1 高可用性&quot;">​</a></h3><h4 id="_5-1-1-快速恢复" tabindex="-1">5.1.1 快速恢复 <a class="header-anchor" href="#_5-1-1-快速恢复" aria-label="Permalink to &quot;5.1.1 快速恢复&quot;">​</a></h4><p>master和chunkserver都要能快速恢复状态。</p><p>可能的异常：kill进程，超时，重连服务器等。</p><h4 id="_5-1-2-chunk复制" tabindex="-1">5.1.2 Chunk复制 <a class="header-anchor" href="#_5-1-2-chunk复制" aria-label="Permalink to &quot;5.1.2 Chunk复制&quot;">​</a></h4><p>每个chunk在不同机架的多个chunkserver上复制。</p><p>当master离线或通过checksum检测到损坏的副本时，master会复制现有副本以保持每个chunk完全复制。</p><h4 id="_5-1-3-master复制" tabindex="-1">5.1.3 master复制 <a class="header-anchor" href="#_5-1-3-master复制" aria-label="Permalink to &quot;5.1.3 master复制&quot;">​</a></h4><p>为保证可靠性，master的状态也是多副本保存。master的操作日志和checkpoint，被复制到多台机器。只有变更日志已经在所有的master副本刷盘，一个变更状态才认为被提交。</p><p>即使在primary master down掉时，shadow master也能够提供文件系统的只读能力。</p><h3 id="_5-2-数据完整性" tabindex="-1">5.2 数据完整性 <a class="header-anchor" href="#_5-2-数据完整性" aria-label="Permalink to &quot;5.2 数据完整性&quot;">​</a></h3><p>GFS的每个chunkserver使用校验和（checksumming）检测数据损坏。</p><p>chunk按照64KB划分，每个都对应32bit的checksum。checksums被保存在内存中，并利用日志持久化。</p><p>对于读请求，chunkserver在返回数据给请求者之前，会验证与读范围重叠的数据块的校验和。如果块的校验和与此前记录的不一致，chunkserver会返回错误给请求者，并将不匹配报告给master。然后，请求者会从其他副本读取数据，而master将从其他副本复制chunk。在一个有效的新副本就位后，master会通知此chunkserver（报告mismatch的）删除其副本。</p><p>GFS客户端通过在校验和边界对齐进行读取操作，使得校验和对读性能影响较小。</p><p>GFS对附加写时的checksum计算也进行了优化。即只增量更新最后一个部分块的checksum，然后对apend操作涉及的新checksum块 计算新的checksums。</p><p>对于覆盖写，GFS必须读取并校验覆盖范围的第一个和最后一个block，然后执行写，最后计算和记录新的checksums。</p><p>在空闲期间，chunkservers会扫描并校验非活跃的chunks。</p><h3 id="_5-3-诊断工具" tabindex="-1">5.3 诊断工具 <a class="header-anchor" href="#_5-3-诊断工具" aria-label="Permalink to &quot;5.3 诊断工具&quot;">​</a></h3><p>GFS通过诊断日志进行问题隔离、调试和性能分析。</p><h2 id="_8-相关" tabindex="-1">8 相关 <a class="header-anchor" href="#_8-相关" aria-label="Permalink to &quot;8 相关&quot;">​</a></h2><p>GFS提供了独立于位置的命名空间，可以透明的移动数据以实现负载均衡或容错。</p><p>由于磁盘相对便宜，GFS目前只使用多副本机制来实现冗余。</p><p>GFS在文件系统接口下，不提供任何缓存。</p><p>GFS选择了中心式服务器的方式，是为了简化设计、提升可靠性、获得灵活性。中心式的master服务器使得复杂的chunk排布和复制策略更简单。GFS通过保持master服务器的状态尽可能小，并且在其他机器上全量复制来容错。可伸缩和高可用性目前由shadow master机制保证。对master的更新通过WAL日志来实现持久化。</p><p>GFS假设大量组件不可靠，因此容错是GFS设计的核心。</p><p>GFS具有重均衡、多副本、恢复等生产环境特性。</p><p>GFS不寻求改变现有存储设备的模型，而是聚焦于基于现有的组件构建分布式系统，来解决日常数据处理的需求。</p><h2 id="_9-结论" tabindex="-1">9 结论 <a class="header-anchor" href="#_9-结论" aria-label="Permalink to &quot;9 结论&quot;">​</a></h2><p>GFS通过持续监控、复制关键数据和快速自动恢复来提供容错功能。Chunk多副本允许容忍chunkserver故障。故障的频率激发了一种新颖的在线修复机制，定期和透明地修复损坏，并尽快补偿丢失的副本。此外，GFS使用checksumming来检测磁盘或IDE子系统级别的数据损坏。</p><p>GFS通过优化网络栈（分离文件系统控制和数据传输）实现了高吞吐。</p><p>本文参考资料：</p><p>Ghemawat, Sanjay, Howard Gobioff, and Shun-Tak Leung. &quot;The Google file system.&quot; <em>Proceedings of the nineteenth ACM symposium on Operating systems principles</em>. 2003.</p>',128)])])}const b=a(c,[["render",i]]);export{_ as __pageData,b as default};
